#include <iostream>
using namespace std;

int main() {
    double num, inverse;

    cout << "Enter a number: ";
    cin >> num;

    if (num == 0) {
        cout << "Inverse does not exist (division by zero)." << endl;
    } else {
        inverse = 1.0 / num;
        cout << "Inverse of " << num << " is: " << inverse << endl;
    }

    return 0;
}
